#!/usr/bin/env bash
# going-paid.sh — 订阅转化 / Going Paid（免费 → 付费订阅） SOP walkthrough for 内容创作者经济(Substack / Beehiiv / 公众号 / 知识星球 / 小报童 / Patreon — newsletter 写作 + 订阅制变现 + 受众沉淀 + 个人 IP).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="内容创作者经济(Substack / Beehiiv / 公众号 / 知识星球 / 小报童 / Patreon — newsletter 写作 + 订阅制变现 + 受众沉淀 + 个人 IP)"
WORKFLOW="订阅转化 / Going Paid（免费 → 付费订阅）"

usage() {
  cat <<EOF
going-paid.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./going-paid.sh             # interactive
  ./going-paid.sh --dry-run
  ./going-paid.sh --json
  ./going-paid.sh --explain
  ./going-paid.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "订阅转化 / Going Paid（免费 → 付费订阅）" 工作流。

一句话: 从「免费 newsletter 有了受众信任」到「开了付费档、有稳定付费订阅收入」。对应 intake 流派 A（subscription-first）的核心子流程,是全生命周期 #1 阶段 3 的一条变现主线。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 平台是聚合者,创作者是租户 — 资产要握在自己手里: newsletter / 创作者经济里,平台(Substack / 公众号)靠控制需求与分发赢,创作者在平台上是租户;真正的资产是「能带走的 email 列表 + 自有域名(海外)/ 私域回流(国内)
  • 「先免费建信任、再变现」的耐心模型: 这一行的资深人默认「受众信任 / 受众深度」是前置资产,变现是它的函数 — 顺序不能反:先把价值无偿给出去、把漏斗顶部做够宽,再谈收费 / 接广告 / 卖课。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**先免费建够信任**:going paid 的前提是免费期已经证明价值——Lenny 免费写约 9 个月才收费是业内常被引的范例。"
  "**定免费 / 付费切分（free-vs-paid ratio）**:决定哪些内容免费(漏斗顶部、拉新)、哪些进付费墙(深度、独家)——这个配比直接决定增长与变现的平衡。"
  "**定价**:海外个人 newsletter 常见 \$10-15/月 或 \$100-150/年;可设高价档(如 \$300+/年含一对一 call)做客单价分层(Aakash 的结构)。"
  "**写「going paid」沟通**:向免费读者讲清「为什么收费、付费能多得到什么、免费内容不会消失」——Aakash 公开过一份「going paid 1-pager」。"
  "**开付费档 + 盯转化**:转化率体感锚点——成熟付费 newsletter 约 4% 免费转付费(Aakash ~4%)。"
  "**盯续订 / churn**:付费收入是「留下来的」不是「拉进来的」,持续监控流失并复盘原因。"
)
declare -a FAILURE_MODES=(
  "**太早全面收费**:受众信任和规模没到,漏斗顶部太窄,付费墙后几乎无人。避免:先免费建信任(参照 Lenny 约 9 个月),漏斗够宽再收窄。"
  "**free-vs-paid 切分失衡**:全免费没收入 / 全付费停增长。避免:留足免费内容做拉新,深度独家进付费墙。"
  "**只看新增不看 churn**:付费基本盘漏水。避免:把续订率 / 流失原因纳入固定复盘。"
  "**只卖「付费文章」单一形态**:2025 语境下竞争力弱。避免:付费档绑社群 / podcast / coaching 做飞轮。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "going-paid-walkthrough"
fi
